diff --git a/src/sidepanel/styles.css b/src/sidepanel/styles.css
new file mode 100644
index 0000000..13cdbb6
--- /dev/null
+++ b/src/sidepanel/styles.css
@@ -0,0 +1,713 @@
+@import "../ui/styles.css";
+
+:root {
+  background: #f6f7f9;
+}
+
+.agent-shell {
+  height: 100vh;
+  display: flex;
+  flex-direction: column;
+  overflow: hidden;
+  background: #f7f8fa;
+  color: #111827;
+}
+
+.topbar {
+  display: grid;
+  grid-template-columns: 34px 1fr auto;
+  align-items: center;
+  gap: 10px;
+  padding: 14px 14px 12px;
+  border-bottom: 1px solid rgba(17, 24, 39, 0.08);
+  background: #ffffff;
+  backdrop-filter: blur(14px);
+  flex-shrink: 0;
+}
+
+.mark {
+  width: 34px;
+  height: 34px;
+  border: 1px solid #d7dce3;
+  border-radius: 8px;
+  display: grid;
+  place-items: center;
+  color: #1f2937;
+  background: #ffffff;
+  box-shadow: 0 1px 2px rgba(15, 23, 42, 0.06);
+}
+
+.brand-copy {
+  min-width: 0;
+}
+
+.brand-title {
+  font-size: 14px;
+  line-height: 18px;
+  font-weight: 720;
+  letter-spacing: 0;
+}
+
+.brand-subtitle {
+  font-size: 11px;
+  line-height: 15px;
+  color: #6b7280;
+}
+
+.topbar-actions {
+  display: flex;
+  gap: 6px;
+  align-items: center;
+}
+
+.icon-button {
+  width: 32px;
+  height: 32px;
+  border: 1px solid transparent;
+  border-radius: 7px;
+  display: grid;
+  place-items: center;
+  background: transparent;
+  color: #4b5563;
+  cursor: pointer;
+}
+
+.icon-button:hover {
+  border-color: #d7dce3;
+  background: #ffffff;
+  color: #111827;
+}
+
+.context-panel {
+  margin: 10px 10px 0;
+  padding: 0;
+  border: 1px solid #e2e8f0;
+  border-radius: 8px;
+  background: #ffffff;
+  box-shadow: 0 1px 2px rgba(15, 23, 42, 0.04);
+  flex-shrink: 0;
+}
+
+.context-summary {
+  width: 100%;
+  min-height: 54px;
+  border-radius: 8px;
+  background: transparent;
+  display: grid;
+  grid-template-columns: minmax(0, 1fr) 30px 30px;
+  gap: 4px;
+  align-items: center;
+  padding: 6px;
+}
+
+.context-summary:hover {
+  background: #f8fafc;
+}
+
+.context-summary-main {
+  min-width: 0;
+  min-height: 42px;
+  display: grid;
+  grid-template-columns: 14px minmax(0, 1fr);
+  gap: 8px;
+  align-items: start;
+  padding: 3px 4px;
+  text-align: left;
+}
+
+.summary-icon-button:hover {
+  background: #eef2f7;
+}
+
+.summary-icon-button {
+  width: 30px;
+  height: 30px;
+  border: 1px solid transparent;
+  border-radius: 7px;
+  display: grid;
+  place-items: center;
+  background: transparent;
+  color: #64748b;
+  cursor: pointer;
+}
+
+.page-summary-copy {
+  min-width: 0;
+  display: block;
+}
+
+.page-summary-copy strong {
+  display: block;
+  color: #111827;
+  font-size: 13px;
+  font-weight: 680;
+  line-height: 17px;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.page-summary-copy small {
+  display: block;
+  margin-top: 2px;
+  color: #64748b;
+  font-size: 11px;
+  line-height: 14px;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.summary-meta {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  justify-content: flex-start;
+  color: #64748b;
+  font-size: 10.5px;
+  line-height: 13px;
+  font-weight: 680;
+  margin-bottom: 3px;
+}
+
+.summary-meta span {
+  white-space: nowrap;
+}
+
+.summary-chevron {
+  color: #64748b;
+  transition: transform 0.16s ease;
+}
+
+.summary-chevron.open {
+  transform: rotate(90deg);
+}
+
+.context-details {
+  padding: 0 10px 10px;
+}
+
+.status-dot {
+  width: 7px;
+  height: 7px;
+  border-radius: 999px;
+  background: #cbd5e1;
+  margin-top: 19px;
+}
+
+.status-dot.ready {
+  background: #0f9f6e;
+  box-shadow: 0 0 0 3px rgba(15, 159, 110, 0.12);
+}
+
+.page-title {
+  color: #111827;
+  font-size: 13px;
+  font-weight: 650;
+  line-height: 18px;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.page-origin {
+  margin-top: 4px;
+  color: #6b7280;
+  font-size: 11px;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.context-grid {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  gap: 6px;
+  margin-top: 10px;
+}
+
+.context-grid > div {
+  border: 1px solid #edf2f7;
+  border-radius: 7px;
+  background: #f8fafc;
+  padding: 7px;
+  min-width: 0;
+}
+
+.context-grid span,
+.permission-row span {
+  display: block;
+  color: #64748b;
+  font-size: 10.5px;
+  line-height: 13px;
+}
+
+.context-grid strong,
+.permission-row strong {
+  display: block;
+  margin-top: 2px;
+  color: #111827;
+  font-size: 11px;
+  line-height: 14px;
+  font-weight: 750;
+}
+
+.model-line {
+  display: flex;
+  align-items: center;
+  gap: 6px;
+  margin-top: 9px;
+  min-width: 0;
+  color: #334155;
+  font-size: 11px;
+}
+
+.model-line span {
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.mode-control {
+  display: grid;
+  grid-template-columns: repeat(3, 1fr);
+  gap: 3px;
+  margin-top: 9px;
+  padding: 3px;
+  border: 1px solid #e2e8f0;
+  border-radius: 7px;
+  background: #f8fafc;
+}
+
+.mode-option {
+  height: 24px;
+  border: 0;
+  border-radius: 5px;
+  background: transparent;
+  color: #64748b;
+  font-size: 11px;
+  font-weight: 700;
+  cursor: pointer;
+}
+
+.mode-option.active {
+  background: #ffffff;
+  color: #111827;
+  box-shadow: 0 1px 2px rgba(15, 23, 42, 0.08);
+}
+
+.permission-row {
+  display: grid;
+  grid-template-columns: 16px 1fr auto;
+  gap: 8px;
+  align-items: center;
+  padding: 8px 9px;
+  border-bottom: 1px solid #edf2f7;
+}
+
+.permission-list {
+  margin-top: 9px;
+  border: 1px solid #e2e8f0;
+  border-radius: 7px;
+  overflow: hidden;
+}
+
+.permission-row:last-child {
+  border-bottom: 0;
+}
+
+.permission-row svg {
+  color: #64748b;
+}
+
+.permission-row strong {
+  margin: 0;
+  text-align: right;
+}
+
+.debugger-gate {
+  border-top: 1px solid #fed7aa;
+  background: #fff7ed;
+  color: #9a3412;
+  padding: 8px 9px;
+  font-size: 11px;
+  line-height: 15px;
+}
+
+.setup-callout {
+  margin: 8px 10px 0;
+  padding: 10px;
+  border: 1px solid #d7dce3;
+  border-radius: 8px;
+  display: grid;
+  grid-template-columns: 1fr auto;
+  gap: 10px;
+  align-items: center;
+  background: #ffffff;
+  flex-shrink: 0;
+}
+
+.setup-title {
+  color: #111827;
+  font-size: 12px;
+  font-weight: 700;
+}
+
+.setup-copy {
+  margin-top: 3px;
+  color: #64748b;
+  font-size: 11px;
+  line-height: 15px;
+}
+
+.setup-button {
+  height: 32px;
+  border: 1px solid #111827;
+  border-radius: 7px;
+  background: #111827;
+  color: #ffffff;
+  padding: 0 10px;
+  font-size: 12px;
+  font-weight: 650;
+  cursor: pointer;
+}
+
+.section-label {
+  color: #64748b;
+  font-size: 10px;
+  line-height: 13px;
+  font-weight: 800;
+  letter-spacing: 0;
+  text-transform: uppercase;
+  margin: 0 0 6px;
+}
+
+.composer-actions {
+  display: flex;
+  gap: 6px;
+  overflow-x: auto;
+  padding-bottom: 8px;
+}
+
+.task-button {
+  height: 30px;
+  border: 1px solid #e2e8f0;
+  border-radius: 999px;
+  background: #ffffff;
+  color: #111827;
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  gap: 8px;
+  padding: 0 10px;
+  flex: 0 0 auto;
+  cursor: pointer;
+  font-size: 11px;
+  font-weight: 720;
+  white-space: nowrap;
+}
+
+.task-button:hover:not(:disabled) {
+  border-color: #cbd5e1;
+  background: #f8fafc;
+}
+
+.task-button:disabled {
+  cursor: not-allowed;
+  opacity: 0.55;
+}
+
+.task-button svg {
+  color: #475569;
+}
+
+.timeline {
+  flex: 1;
+  min-height: 0;
+  overflow: auto;
+  padding: 8px 10px 12px;
+  display: flex;
+  flex-direction: column;
+  gap: 7px;
+}
+
+.timeline-row {
+  display: grid;
+  grid-template-columns: 22px minmax(0, 1fr);
+  gap: 8px;
+  align-items: start;
+}
+
+.timeline-marker {
+  width: 22px;
+  height: 22px;
+  border: 1px solid #e2e8f0;
+  border-radius: 999px;
+  display: grid;
+  place-items: center;
+  background: #f8fafc;
+  color: #64748b;
+  font-size: 9px;
+  font-weight: 700;
+}
+
+.timeline-card {
+  border: 1px solid #e2e8f0;
+  border-radius: 7px;
+  background: #ffffff;
+  color: #1f2937;
+  padding: 8px 9px;
+  box-shadow: 0 1px 2px rgba(15, 23, 42, 0.04);
+}
+
+.timeline-row.user .timeline-card {
+  border-color: #111827;
+}
+
+.timeline-row.blocked .timeline-card,
+.timeline-row.error .timeline-card {
+  border-color: #fed7aa;
+  background: #fff7ed;
+  color: #9a3412;
+}
+
+.timeline-title {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: 8px;
+  font-size: 11px;
+  line-height: 14px;
+  font-weight: 780;
+}
+
+.timeline-title em {
+  color: #64748b;
+  font-style: normal;
+  font-size: 10px;
+  font-weight: 650;
+  flex-shrink: 0;
+}
+
+.timeline-detail {
+  margin-top: 3px;
+  color: #334155;
+  font-size: 12px;
+  line-height: 16px;
+  white-space: pre-wrap;
+}
+
+.timeline-row.blocked .timeline-detail,
+.timeline-row.error .timeline-detail {
+  color: #9a3412;
+}
+
+.timeline-card.working {
+  color: #475569;
+}
+
+.timeline-card.working .timeline-title {
+  display: flex;
+  align-items: center;
+}
+
+.timeline-row.reasoning .timeline-marker svg,
+.send-button svg {
+  flex-shrink: 0;
+}
+
+.timeline-card.working + svg,
+.timeline-row.reasoning .timeline-marker svg,
+.send-button .spinner {
+  animation: spin 0.9s linear infinite;
+}
+
+.composer {
+  padding: 11px 12px 12px;
+  border-top: 1px solid rgba(17, 24, 39, 0.08);
+  background: #ffffff;
+  backdrop-filter: blur(14px);
+  flex-shrink: 0;
+  position: sticky;
+  bottom: 0;
+}
+
+.model-selector-row {
+  display: flex;
+  gap: 6px;
+  align-items: center;
+  justify-content: flex-start;
+  margin-top: 7px;
+}
+
+.model-selector-row > svg {
+  color: #64748b;
+}
+
+.model-select-trigger {
+  width: 178px;
+  max-width: 54vw;
+  height: 28px;
+  border-radius: 7px;
+  box-shadow: none;
+  padding: 0 7px;
+  font-size: 11px;
+  color: #334155;
+}
+
+.model-select-trigger span {
+  min-width: 0;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.model-select-content {
+  max-height: 260px;
+}
+
+.model-select-group {
+  padding: 6px 8px 4px;
+  color: #64748b;
+  font-size: 10px;
+  line-height: 13px;
+  font-weight: 800;
+  text-transform: uppercase;
+}
+
+.composer-shell {
+  display: grid;
+  grid-template-columns: 1fr 34px;
+  gap: 8px;
+  align-items: end;
+  border: 1px solid #d7dce3;
+  border-radius: 10px;
+  background: #fbfcfe;
+  padding: 7px;
+  box-shadow: 0 2px 8px rgba(15, 23, 42, 0.05);
+  transition: border-color 0.15s ease, background 0.15s ease, box-shadow 0.15s ease;
+}
+
+.composer-shell:focus-within {
+  border-color: #94a3b8;
+  background: #ffffff;
+  box-shadow: 0 0 0 2px rgba(148, 163, 184, 0.18);
+}
+
+.composer-input {
+  min-height: 42px;
+  max-height: 130px;
+  border: 0 !important;
+  outline: none !important;
+  resize: none;
+  color: #111827;
+  background: transparent;
+  font-size: 13px;
+  line-height: 18px;
+  padding: 4px 2px;
+  box-shadow: none !important;
+  ring: 0;
+}
+
+.composer-input:focus,
+.composer-input:focus-visible {
+  outline: none !important;
+  box-shadow: none !important;
+}
+
+.composer-input::placeholder {
+  color: #94a3b8;
+}
+
+.send-button {
+  width: 34px;
+  height: 34px;
+  border: 0;
+  border-radius: 10px;
+  display: grid;
+  place-items: center;
+  background: #111827;
+  color: #ffffff;
+  cursor: pointer;
+}
+
+.send-button:disabled {
+  background: #cbd5e1;
+  cursor: not-allowed;
+}
+
+.composer-meta {
+  margin-top: 7px;
+  color: #64748b;
+  font-size: 10.5px;
+  line-height: 14px;
+}
+
+.benchmark-actions {
+  margin-top: 8px;
+}
+
+.artifact-preview,
+.report-preview {
+  margin-top: 10px;
+  display: grid;
+  gap: 8px;
+}
+
+.artifact-preview img {
+  width: 100%;
+  max-height: 280px;
+  object-fit: contain;
+  border: 1px solid #d7dce3;
+  border-radius: 8px;
+  background: #f8fafc;
+}
+
+.report-preview > div {
+  max-height: 360px;
+  overflow: auto;
+  border: 1px solid #d7dce3;
+  border-radius: 8px;
+  background: #ffffff;
+  color: #111827;
+  padding: 12px;
+  font-size: 12px;
+  line-height: 17px;
+}
+
+.report-preview h1,
+.report-preview h2,
+.report-preview h3 {
+  margin: 0 0 8px;
+  color: #111827;
+  font-size: 14px;
+  line-height: 19px;
+}
+
+.report-preview p,
+.report-preview ul,
+.report-preview ol {
+  margin: 0 0 8px;
+}
+
+.artifact-export {
+  justify-self: start;
+  height: 28px;
+  display: inline-flex;
+  align-items: center;
+  gap: 6px;
+  border: 1px solid #cbd5e1;
+  border-radius: 7px;
+  background: #ffffff;
+  color: #334155;
+  padding: 0 9px;
+  font-size: 11px;
+  font-weight: 700;
+  cursor: pointer;
+}
+
+@keyframes spin {
+  to {
+    transform: rotate(360deg);
+  }
+}
